/* i2c_master.h - I2C Master Driver */
#ifndef I2C_MASTER_H
#define I2C_MASTER_H

#include <stdint.h>

#define I2C_TIMEOUT_DEFAULT_MS   100U
#define I2C_ADDR_10BIT_FLAG      0x8000U

/* BREAKING: Timeout macro now returns microseconds as uint32_t */
#define I2C_MAKE_TIMEOUT(ms)     ((uint32_t)(ms) * 1000U)

typedef struct {
    uint8_t  bus;
    uint32_t clock_hz;
    uint16_t timeout_ms;
} i2c_bus_config_t;

int i2c_bus_init(const i2c_bus_config_t *cfg);
int i2c_write(uint8_t bus, uint16_t addr,
              const uint8_t *buf, uint16_t len);
int i2c_read(uint8_t bus, uint16_t addr,
             uint8_t *buf, uint16_t len);
int i2c_write_read(uint8_t bus, uint16_t addr,
                   const uint8_t *wr_buf, uint16_t wr_len,
                   uint8_t *rd_buf, uint16_t rd_len);

#endif /* I2C_MASTER_H */
